select ord.CHNG_ORDER_PROC_ID
    , ord.ORDER_PROC_ID
    , ord.PAT_ID
    , ord.ORDER_TIME
    , ord_i.*
    , ord_child.ORDER_PROC_ID
    , ord_child.CHNG_ORDER_PROC_ID
from order_proc ord
    inner join order_instantiated ord_i on ord.order_proc_id = ord_i.ORDER_ID
    inner join order_proc ord_child on ord_i.INSTNTD_ORDER_ID = ord_child.ORDER_PROC_ID
